  ('aboriginal-f0899a01-moex-00495', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '下列何者非屬罪刑法定原則之內涵？', '["禁止類推適用原則", "禁止習慣法原則", "禁止溯及既往原則", "平等原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
